function initCountdown(){document.querySelectorAll(".timerevent").forEach(e=>{const i=e.getAttribute("data-inizio"),r=e.getAttribute("data-fine"),a=e.getAttribute("data-biglietti");if(!i)return;const s=new Date;s.setHours(0,0,0,0);const o=new Date(i);o.setHours(0,0,0,0);const c=r?new Date(r):new Date(i);c.setHours(0,0,0,0);let t="",n="";if(s>=o&&s<=c)t="🚀 CI SIAMO!",n="in-corso";else if(s<o){const e=Math.ceil((o-s)/(1e3*60*60*24));e===1?(t="⏰ DOMANI! Preparati!",n="urgente"):e<=3?(t=`🔥 SOLO ${e} GIORNI! Non aspettare!`,n="urgente"):e<=7?(t=`✨ Tra ${e} giorni<br>► Prenota il tuo posto!`,n="presto"):e<=15?(t=`📅 Mancano ${e} giorni<br>► Prenota adesso`,n="normale"):(t=`📅 Mancano ${e} giorni<br> 📢 Iscrizioni aperte`,n="futuro")}else{e.style.display="none";return}a&&a.trim()!==""&&(t+=`${a}`),e.innerHTML=`<span class="countdown-${n}">${t}</span>`})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",initCountdown):initCountdown()